import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const PostProductPage = () => {
  const navigate = useNavigate();
  const [step, setStep] = useState(1); // 1: Chọn danh mục, 2: Điền thông tin
  const [selectedCat, setSelectedCat] = useState(null);

  // Dữ liệu Form
  const [formData, setFormData] = useState({
    name: '', price: '', image: '', description: '', location: 'TP. Hồ Chí Minh'
  });
  
  // Dữ liệu chi tiết riêng (Dynamic)
  const [details, setDetails] = useState({});

  // Cấu hình danh mục và các câu hỏi riêng
  const categories = [
    { 
      id: 'bds', name: 'Bất động sản', icon: '🏠',
      questions: [
        { key: 'area', label: 'Diện tích (m2)', type: 'number' },
        { key: 'bedrooms', label: 'Số phòng ngủ', type: 'number' },
        { key: 'direction', label: 'Hướng nhà', type: 'text' }
      ]
    },
    { 
      id: 'xe', name: 'Xe cộ', icon: '🛵',
      questions: [
        { key: 'brand', label: 'Hãng xe', type: 'text' }, // Sau này có thể làm menu thả xuống
        { key: 'year', label: 'Năm sản xuất', type: 'number' },
        { key: 'km', label: 'Số KM đã đi', type: 'number' }
      ]
    },
    { 
      id: 'dientu', name: 'Đồ điện tử', icon: '📱',
      questions: [
        { key: 'brand', label: 'Hãng sản xuất', type: 'text' },
        { key: 'warranty', label: 'Bảo hành (tháng)', type: 'number' },
        { key: 'color', label: 'Màu sắc', type: 'text' }
      ]
    },
    { 
      id: 'vieclam', name: 'Việc làm', icon: '💼',
      questions: [
        { key: 'salary', label: 'Mức lương', type: 'text' },
        { key: 'position', label: 'Vị trí', type: 'text' }
      ]
    },
    { id: 'thucung', name: 'Thú cưng', icon: '🐶', questions: [] }, // Không có câu hỏi riêng
    { id: 'tulanh', name: 'Tủ lạnh', icon: '❄️', questions: [] },
  ];

  // Xử lý chọn danh mục
  const handleSelectCategory = (cat) => {
    setSelectedCat(cat);
    setStep(2); // Chuyển sang bước điền form
    setDetails({}); // Reset chi tiết
  };

  // Xử lý gửi form
  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await axios.post('http://localhost:5000/api/products', {
        ...formData,
        category: selectedCat.name,
        details: details // Gửi kèm thông tin riêng
      });
      alert('Đăng tin thành công!');
      navigate('/');
    } catch (error) {
      alert('Lỗi: ' + error.response?.data?.message || 'Không thể đăng tin');
    }
  };

  return (
    <div className="container py-5" style={{maxWidth: '700px'}}>
      
      {/* --- BƯỚC 1: CHỌN DANH MỤC --- */}
      {step === 1 && (
        <div className="card shadow border-0">
           <div className="card-header bg-white border-bottom-0 pt-4 pb-0 text-center">
              <h4 className="fw-bold">Bạn muốn đăng bán gì?</h4>
              <p className="text-muted">Chọn danh mục phù hợp để tiếp cận người mua tốt nhất</p>
           </div>
           <div className="card-body p-4">
              <div className="row g-3">
                 {categories.map(cat => (
                    <div className="col-4 col-md-4" key={cat.id}>
                       <div 
                          className="card h-100 text-center py-3 border-0 shadow-sm category-hover" 
                          style={{cursor: 'pointer', backgroundColor: '#f8f9fa'}}
                          onClick={() => handleSelectCategory(cat)}
                        >
                          <div style={{fontSize: '40px', marginBottom: '10px'}}>{cat.icon}</div>
                          <div className="fw-bold">{cat.name}</div>
                       </div>
                    </div>
                 ))}
              </div>
           </div>
        </div>
      )}

      {/* --- BƯỚC 2: ĐIỀN THÔNG TIN --- */}
      {step === 2 && (
        <div className="card shadow border-0 animate__animated animate__fadeIn">
          <div className="card-header bg-chotot text-dark d-flex align-items-center">
            <button className="btn btn-sm btn-light me-3" onClick={() => setStep(1)}>⬅ Quay lại</button>
            <h5 className="mb-0 fw-bold">Đăng tin: {selectedCat.name}</h5>
          </div>
          <div className="card-body p-4">
            <form onSubmit={handleSubmit}>
              
              {/* 1. THÔNG TIN CƠ BẢN (Chung cho tất cả) */}
              <h6 className="fw-bold text-primary mb-3">Thông tin chung</h6>
              <div className="mb-3">
                <label className="form-label">Tên sản phẩm / Tiêu đề</label>
                <input type="text" className="form-control" required 
                  onChange={(e) => setFormData({...formData, name: e.target.value})} 
                  placeholder={`Ví dụ: Bán ${selectedCat.name} giá rẻ...`}
                />
              </div>
              
              <div className="row">
                 <div className="col-md-6 mb-3">
                    <label className="form-label">Giá bán (VNĐ)</label>
                    <input type="number" className="form-control" required 
                      onChange={(e) => setFormData({...formData, price: e.target.value})} 
                    />
                 </div>
                 <div className="col-md-6 mb-3">
                    <label className="form-label">Khu vực</label>
                    <select className="form-select" 
                      onChange={(e) => setFormData({...formData, location: e.target.value})}
                    >
                       <option>TP. Hồ Chí Minh</option>
                       <option>Hà Nội</option>
                       <option>Đà Nẵng</option>
                       <option>Cần Thơ</option>
                    </select>
                 </div>
              </div>

              {/* 2. THÔNG TIN RIÊNG (Dynamic Fields) */}
              {selectedCat.questions.length > 0 && (
                <div className="bg-light p-3 rounded mb-3">
                  <h6 className="fw-bold text-primary mb-3">Chi tiết {selectedCat.name}</h6>
                  <div className="row">
                    {selectedCat.questions.map(q => (
                       <div className="col-md-6 mb-3" key={q.key}>
                          <label className="form-label">{q.label}</label>
                          <input 
                            type={q.type} 
                            className="form-control"
                            required
                            onChange={(e) => setDetails({...details, [q.key]: e.target.value})}
                          />
                       </div>
                    ))}
                  </div>
                </div>
              )}

              {/* 3. HÌNH ẢNH & MÔ TẢ */}
              <div className="mb-3">
                <label className="form-label">Link Hình ảnh</label>
                <input type="text" className="form-control" required
                  onChange={(e) => setFormData({...formData, image: e.target.value})}
                  placeholder="http://..."
                />
              </div>
              {formData.image && <img src={formData.image} alt="Preview" className="mb-3 rounded" style={{height: '100px'}} />}

              <div className="mb-3">
                <label className="form-label">Mô tả chi tiết</label>
                <textarea className="form-control" rows="4" required
                  onChange={(e) => setFormData({...formData, description: e.target.value})}
                  placeholder="Mô tả chi tiết về sản phẩm..."
                ></textarea>
              </div>

              <button type="submit" className="btn btn-chotot w-100 fw-bold py-2 fs-5">ĐĂNG TIN NGAY</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default PostProductPage;
